import{_ as t,o as a,c as s,aj as n}from"./chunks/framework.RhfyOUxy.js";const h=JSON.parse('{"title":"Presentation","description":"","frontmatter":{},"headers":[],"relativePath":"guide/presentation.md","filePath":"guide/presentation.md"}'),r={name:"guide/presentation.md"};function o(i,e,d,p,l,c){return a(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="presentation" tabindex="-1">Presentation <a class="header-anchor" href="#presentation" aria-label="Permalink to &quot;Presentation&quot;">​</a></h1><p><strong>TopSolid MCP</strong> est un serveur <a href="https://modelcontextprotocol.io/" target="_blank" rel="noreferrer">Model Context Protocol</a> qui permet a un agent IA de piloter le logiciel CAO/PDM <strong>TopSolid 7</strong> via son API Automation.</p><h2 id="comment-ca-marche" tabindex="-1">Comment ca marche <a class="header-anchor" href="#comment-ca-marche" aria-label="Permalink to &quot;Comment ca marche&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent IA (OpenClaw / Claude / tout client MCP)</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>  v</span></span>
<span class="line"><span>TopSolidMcpServer.exe (stdio JSON-RPC)</span></span>
<span class="line"><span>  |  - run_recipe : execute une des 113 recettes pre-construites</span></span>
<span class="line"><span>  |  - api_help : cherche les bonnes methodes API (52 synonymes FR)</span></span>
<span class="line"><span>  |  - execute_script : compile et execute du C# contre TopSolid</span></span>
<span class="line"><span>  |  - find_path / explore_paths : navigue dans le graphe de types</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>  v</span></span>
<span class="line"><span>TopSolid 7 (WCF/TCP port 8090)</span></span></code></pre></div><p>L&#39;agent pose une question en langage naturel → le serveur MCP traduit en appels API → TopSolid execute.</p><h2 id="composants" tabindex="-1">Composants <a class="header-anchor" href="#composants" aria-label="Permalink to &quot;Composants&quot;">​</a></h2><h3 id="graphe-api-enrichi-graph-json" tabindex="-1">Graphe API enrichi (<code>graph.json</code>) <a class="header-anchor" href="#graphe-api-enrichi-graph-json" aria-label="Permalink to &quot;Graphe API enrichi (\`graph.json\`)&quot;">​</a></h3><p>Le coeur du systeme. Un graphe oriente representant toutes les methodes de l&#39;API TopSolid Automation :</p><table tabindex="0"><thead><tr><th>Metrique</th><th>Valeur</th></tr></thead><tbody><tr><td>Edges</td><td>4119</td></tr><tr><td>Methodes uniques</td><td>1728</td></tr><tr><td>Interfaces</td><td>46</td></tr><tr><td>Description</td><td>90%</td></tr><tr><td>Hints semantiques</td><td>85%</td></tr><tr><td>Edges avec exemples reels</td><td>1194 (29%)</td></tr><tr><td>Snippets de code</td><td>2174</td></tr></tbody></table><h3 id="serveur-mcp-topsolidmcpserver-exe" tabindex="-1">Serveur MCP (<code>TopSolidMcpServer.exe</code>) <a class="header-anchor" href="#serveur-mcp-topsolidmcpserver-exe" aria-label="Permalink to &quot;Serveur MCP (\`TopSolidMcpServer.exe\`)&quot;">​</a></h3><p>Executable .NET Framework 4.8, communique en stdio JSON-RPC. <strong>7 outils</strong> exposes a l&#39;agent.</p><h3 id="recipetool-—-113-recettes" tabindex="-1">RecipeTool — 113 recettes <a class="header-anchor" href="#recipetool-—-113-recettes" aria-label="Permalink to &quot;RecipeTool — 113 recettes&quot;">​</a></h3><p>L&#39;outil principal. Le LLM choisit une recette par nom, aucune generation de code necessaire.</p><table tabindex="0"><thead><tr><th>Categorie</th><th>Recettes</th><th>Exemples</th></tr></thead><tbody><tr><td>PDM (lecture/ecriture)</td><td>9</td><td>designation, reference, fabricant</td></tr><tr><td>Navigation projet</td><td>5</td><td>chercher, ouvrir, lister documents</td></tr><tr><td>Parametres</td><td>6</td><td>lire, modifier, comparer</td></tr><tr><td>Masse/Volume/Dimensions</td><td>7</td><td>masse, volume, surface, inertie, boite englobante</td></tr><tr><td>Geometrie/Visualisation</td><td>8</td><td>shapes, esquisses, operations, couleurs</td></tr><tr><td>Assemblages</td><td>6</td><td>inclusions, occurrences, comptage pieces</td></tr><tr><td>Export</td><td>8</td><td>STEP, DXF, PDF, STL, IGES, CSV</td></tr><tr><td>Mise en plan</td><td>6</td><td>vues, echelle, format, projection, ouvrir plan</td></tr><tr><td>Nomenclature (BOM)</td><td>4</td><td>colonnes, contenu, comptage lignes</td></tr><tr><td>Mise a plat / Tolerie</td><td>3</td><td>detection, plis, dimensions depliage</td></tr><tr><td>Comparaison documents</td><td>4</td><td>parametres, operations, entites, revisions</td></tr><tr><td>Report modifications</td><td>2</td><td>copier parametres ou proprietes PDM vers un autre doc</td></tr><tr><td>Batch projet</td><td>13</td><td>audit refs/desig, masse batch, export batch, auteur, virtuel</td></tr><tr><td>Audit qualite</td><td>6</td><td>noms parametres, drivers famille, materiaux</td></tr><tr><td>Familles</td><td>5</td><td>detection, catalogue, drivers</td></tr><tr><td>Historique/Revisions</td><td>2</td><td>timeline revisions, comparaison revisions</td></tr><tr><td>Document</td><td>7</td><td>type, sauvegarder, reconstruire, proprietes utilisateur</td></tr><tr><td>Interactif</td><td>3</td><td>selection shape/face/point dans TopSolid</td></tr></tbody></table><h3 id="dataset-lora-lora-dataset-jsonl" tabindex="-1">Dataset LoRA (<code>lora-dataset.jsonl</code>) <a class="header-anchor" href="#dataset-lora-lora-dataset-jsonl" aria-label="Permalink to &quot;Dataset LoRA (\`lora-dataset.jsonl\`)&quot;">​</a></h3><p>2161 paires d&#39;entrainement au format ShareGPT pour fine-tuner un modele 3B sur la selection de recettes. Couvre les 112 recettes avec variantes francais naturel/metier et paires d&#39;ambiguite Smart params.</p><h3 id="tests" tabindex="-1">Tests <a class="header-anchor" href="#tests" aria-label="Permalink to &quot;Tests&quot;">​</a></h3><p>Suite de tests automatises contre une instance TopSolid vivante. Scripts PowerShell executables en batch.</p><h2 id="architecture-agent-openclaw" tabindex="-1">Architecture Agent (OpenClaw) <a class="header-anchor" href="#architecture-agent-openclaw" aria-label="Permalink to &quot;Architecture Agent (OpenClaw)&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>OpenClaw Main (cloud, leger — routing + conversation)</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>  ├── topsolid-recipes (3B LoRA, local)</span></span>
<span class="line"><span>  |     → topsolid_run_recipe</span></span>
<span class="line"><span>  |     113 recettes pre-construites</span></span>
<span class="line"><span>  |     Classification : intent → nom de recette</span></span>
<span class="line"><span>  |     Latence : ~2-4 secondes</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>  └── topsolid-automation (14-24B, local — a venir)</span></span>
<span class="line"><span>        → topsolid_execute_script + api_help + find_path</span></span>
<span class="line"><span>        Generation C# via le graphe API</span></span>
<span class="line"><span>        Cas hors-recettes, scripts ad-hoc</span></span>
<span class="line"><span>        Latence cible : &lt; 30 secondes</span></span></code></pre></div><p>Le Main (cloud) garde la coherence conversationnelle et route les demandes :</p><ul><li><strong>Recette connue</strong> (80% des cas) → sous-agent 3B, rapide et fiable</li><li><strong>Cas custom</strong> (20%) → sous-agent 14-24B, generation de code via le graphe</li></ul><p>Le LoRA cible le 3B pour ameliorer sa connaissance TopSolid. Un second LoRA (futur) ciblera le 14-24B pour la generation C#.</p><h2 id="projet-cortana-noemid" tabindex="-1">Projet Cortana / Noemid <a class="header-anchor" href="#projet-cortana-noemid" aria-label="Permalink to &quot;Projet Cortana / Noemid&quot;">​</a></h2><p>TopSolid MCP fait partie du projet <strong>Cortana</strong> (prototype) qui migre vers <strong>Noemid</strong> (produit final). Le serveur MCP et le graphe API sont les composants qui survivent a la migration.</p>`,25)])])}const m=t(r,[["render",o]]);export{h as __pageData,m as default};
